{"command": "python3 -c "
content = open('/mnt/data/Developing/hermes-workspace/tasks/TASKS.md', 'r', encoding='utf-8').read()
lines = content.split('\n')

in_done = False
done_entries = []
task_log_entries = []

for line in lines:
    stripped = line.strip()
    if stripped == '==DONE==':
        in_done = True
        continue
    if stripped == '==TASKS==':
        in_done = False
        continue
    if not line.startswith('- '):
        continue
    # Parse: date_created;tag;status;title;description
    parts = line[2:].split(';', 4)
    if len(parts) < 5:
        continue
    date_created, tag, status, title, description = parts

    if in_done:
        if date_created.startswith('15-06') or date_created.startswith('16-06') or date_created.startswith('17-06') or date_created.startswith('18-06') or date_created.startswith('19-06'):
            done_entries.append((date_created, tag, status, title, description))
    else:
        # Check for week-dated log entries
        import re
        week_dates = re.findall(r'(Mon|Tue|Wed|Thu|Fri) Jun (1[5-9]):', description)
        if week_dates:
            task_log_entries.append((date_created, tag, status, title, description))

print('=== DONE ENTRIES THIS WEEK ===')
for e in done_entries:
    print(f'{e[0]};{e[1]};{e[3]};{e[4][:80]}')
print()
print('=== TASKS WITH WEEK LOGS ===')
for e in task_log_entries:
    print(f'{e[0]};{e[1]};{e[3]}')
""}
